use wasm_bindgen::prelude::*;

// Vec<u8> JS'e döndür
#[wasm_bindgen]
pub fn process_bytes(input: &[u8]) -> Vec<u8> {
    input.iter().map(|b| b.wrapping_add(1)).collect()
}

// JS Float64Array ile sıfır kopya
#[wasm_bindgen]
pub fn sum_array(arr: &[f64]) -> f64 {
