## web-sys DOM
```rust
use wasm_bindgen::prelude::*;
use web_sys::{Document, HtmlElement};

#[wasm_bindgen]
pub fn update_dom() {
    let window = web_sys::window().unwrap();
    let document: Document = window.document().unwrap();

    let el: HtmlElement = document
        .get_element_by_id("output")
        .unwrap()
        .dyn_into::<HtmlElement>()
        .unwrap();

    el.set_inner_text("Rust'tan Merhaba!");
}
```

## WASM Yükleme
```javascript
// Önerilen: streaming (sunucudan)
const { instance, module } = await WebAssembly.instantiateStreaming(
  fetch('/app.wasm'),
  { env: { log: (ptr, len) => console.log(readString(ptr, len)) } }
);

// Alternatif: ArrayBuffer
const bytes = await (await fetch('/app.wasm')).arrayBuffer();
const { instance } = await WebAssembly.instantiate(bytes, {});

// Module önbelleğe al
const cachedModule = await WebAssembly.compileStreaming(fetch('/app.wasm'));
const inst1 = await WebAssembly.instantiate(cachedModule);
const inst2 = await WebAssembly.instantiate(cachedModule);
```

